const AWS = require('aws-sdk');
const childProcess = require('child_process');

exports.handler = async (event) => {
    const s3 = new AWS.S3({ region: process.env.AWS_REGION });
    
    if (event.Records.length === 0 || !event.Records[0].s3 || !event.Records[0].s3.objectKey) {
        console.log('No object was uploaded');
        return;
    }
    
    const sourceBucket = event.Records[0].s3.bucket.name;
    const destinationBucket = process.env.DESTINATION_BUCKET_NAME;
    const inputFile = event.Records[0].s3.objectKey;
    const outputFileFormat = event.Records[0].eventSourceTriggerEventDetails.outputFormat;
    
    const command = `convert ${inputFile} output.${outputFileFormat}`;
    try {
        childProcess.execSync(command, { cwd: '/tmp' });
        
        const copyParams = {
            SourceBucket: sourceBucket,
            SourceKey: inputFile,
            DestinationBucket: destinationBucket,
            DestinationKey: `${process.env.PREFIX}/output.${outputFileFormat}`
        };
        
        s3.copyObject(copyParams, (err, data) => {
            if (err) console.log(err);
            else console.log(data);
        });
    } catch (e) {
        console.log(`An error occurred ${e}`);
    }
};